callGraph.callee:
updateRows(context, 'coupon_redemptions', { id: existingRedemption[0].id }, {
        status: 'used',
        metadata: { source: 'iyzico_callback', previous_status: existingRedemption[0].status || null },
        updated_at: now
      }).catch

updateRows(context, 'customer_coupons', { user_id: order.user_id, code: order.coupon_code }, {
        status: 'used', used_at: now, order_id: orderId, updated_at: now
      }).catch

updateRows(context, 'customer_coupons', { customer_email: String(order.customer_email).toLowerCase(), code: order.coupon_code }, {
        status: 'used', used_at: now, order_id: orderId, updated_at: now
      }).catch

updateRows(context, 'payments', { id: payment.id }, {
      status: 'paid',
      raw_callback_response: {
        source: 'admin_manual_bank_transfer',
        approved_by_email: approvedByEmail || null,
        approved_by_admin_id: approvedByAdminId || null,
        confirmed_at: now
      },
      updated_at: now
    }).catch

updateRows(context, 'payments', { id: payment.id }, {
      status: 'failed',
      raw_callback_response: {
        source: 'admin_manual_bank_transfer_rejection',
        rejected_by_email: rejectedByEmail || null,
        rejected_by_admin_id: rejectedByAdminId || null,
        reason: reason || null,
        confirmed_at: now
      },
      updated_at: now
    }).catch

updateRows(context, 'orders', { id: orderId }, {
      payment_status: 'failed',
      status: order.status === 'cancelled' ? order.status : 'cancelled',
      fulfillment_status: 'cancelled',
      updated_at: now
    }).catch

updateRows(context, 'coupon_redemptions', { order_id: orderId }, {
        status: 'released',
        metadata: { source: 'admin_bank_transfer_rejection' },
        updated_at: now
      }).catch

updateRows(context, 'restock_alerts', { id: alert.id }, {
          last_attempt_at: new Date().toISOString(),
          last_error: result.reason || 'email_skipped'
        }).catch

updateRows(context, 'restock_alerts', { id: alert.id }, {
        last_attempt_at: new Date().toISOString(),
        last_error: String(error?.message || 'email_error').slice(0, 500)
      }).catch

(cart || []).map((item) => ({
    product_slug: normalizeSlug(item.product_slug || item.slug || item.product_id || item.id),
    quantity: Math.max(1, Math.floor(Number(item.quantity ?? item.qty ?? 1) || 1)),
    product_name: item.product_name || item.name || item.product_slug || item.id || 'Ürün'
  })).filter

catalogProducts().map((product) => {
      const row = map.get(product.slug) || normalizeInventoryRow({ product_slug: product.slug, stock_on_hand: 0, stock_reserved: 0, status: 'active' });
      const flags = {
        in_stock: row.status === 'active' && (row.allow_backorder || row.available_stock > 0),
        low_stock: row.status === 'active' && row.available_stock > 0 && row.available_stock <= row.low_stock_threshold,
        out_of_stock: row.status === 'active' && !row.allow_backorder && row.available_stock <= 0
      };
      return { ...product, sku: row.sku || product.slug.toUpperCase().replace(/-/g, '_'), inventory: row, flags };
    }).filter
